 13	export const expandIPv6 = (ipV6: string): string => {
 14	  const sections = ipV6.split(':')
 15	  if (IPV4_REGEX.test(sections.at(-1) as string)) {
 16	    sections.splice(
 17	      -1,
 18	      1,
 19	      ...convertIPv6BinaryToString(convertIPv4ToBinary(sections.at(-1) as string)) // => ::7f00:0001
 20	        .substring(2) // => 7f00:0001
 21	        .split(':') // => ['7f00', '0001']
 22	    )
 23	  }
 24	  for (let i = 0; i < sections.length; i++) {
 25	    const node = sections[i]
 26	    if (node !== '') {
 27	      sections[i] = node.padStart(4, '0')
 28	    } else {
 29	      sections[i + 1] === '' && sections.splice(i + 1, 1)
 30	      sections[i] = new Array(8 - sections.length + 1).fill('0000').join(':')
 31	    }
 32	  }
 33	  return sections.join(':')
 34	}
