  8	const parseIPv4ToParts = (ipv4: string): number[] | undefined => {
  9	  const parts = ipv4.split('.')
 10	  if (parts.length !== 4) {
 11	    return
 12	  }
 13	
 14	  const parsed = []
 15	  for (const part of parts) {
 16	    if (part.length === 0 || (part.length > 1 && part[0] === '0')) {
 17	      return
 18	    }
 19	
 20	    let value = 0
 21	    for (let i = 0; i < part.length; i++) {
 22	      const code = part.charCodeAt(i)
 23	      if (code < 48 || code > 57) {
 24	        return
 25	      }
 26	      value = value * 10 + code - 48
 27	    }
 28	
 29	    if (value > 255) {
 30	      return
 31	    }
 32	    parsed.push(value)
 33	  }
 34	
 35	  return parsed
 36	}
 37	
 38	const isIPv6Segment = (segment: string): boolean => {
 39	  if (segment.length === 0 || segment.length > 4) {
 40	    return false
 41	  }
 42	  for (let i = 0; i < segment.length; i++) {
 43	    const code = segment.charCodeAt(i)
 44	    if (
 45	      !(
 46	        (code >= 48 && code <= 57) ||
 47	        (code >= 65 && code <= 70) ||
 48	        (code >= 97 && code <= 102)
 49	      )
 50	    ) {
 51	      return false
 52	    }
 53	  }
 54	  return true
 55	}
