 57	const parseIPv6ToParts = (ipv6: string): number[] | undefined => {
 58	  let addr = ipv6
 59	  const ipv4Start = ipv6.lastIndexOf(':')
 60	  const ipv4Parts =
 61	    ipv6.includes('.') && ipv4Start !== -1 ? parseIPv4ToParts(ipv6.slice(ipv4Start + 1)) : undefined
 62	  if (ipv6.includes('.') && ipv4Parts === undefined) {
 63	    return
 64	  }
 65	  if (ipv4Parts) {
 66	    addr = `${ipv6.slice(0, ipv4Start)}:${((ipv4Parts[0] << 8) | ipv4Parts[1]).toString(
 67	      16
 68	    )}:${((ipv4Parts[2] << 8) | ipv4Parts[3]).toString(16)}`
 69	  }
 70	
 71	  const compressed = addr.split('::')
 72	  if (compressed.length > 2) {
 73	    return
 74	  }
 75	
 76	  const left = compressed[0] ? compressed[0].split(':') : []
 77	  const right = compressed.length === 2 && compressed[1] ? compressed[1].split(':') : []
 78	  if (left.some((part) => !isIPv6Segment(part)) || right.some((part) => !isIPv6Segment(part))) {
 79	    return
 80	  }
 81	
 82	  if (compressed.length === 1) {
 83	    if (left.length !== 8) {
 84	      return
 85	    }
 86	    return left.map((part) => parseInt(part, 16))
 87	  }
 88	
 89	  const zeroCount = 8 - left.length - right.length
 90	  if (zeroCount <= 0) {
 91	    return
 92	  }
 93	
 94	  return [
 95	    ...left.map((part) => parseInt(part, 16)),
 96	    ...new Array(zeroCount).fill(0),
 97	    ...right.map((part) => parseInt(part, 16)),
 98	  ]
 99	}
