 39	  const separatorIndex = rule.indexOf('/')
 40	  if (separatorIndex === -1) {
 41	    return
 42	  }
 43	  if (separatorIndex !== rule.lastIndexOf('/')) {
 44	    throw new TypeError(`Invalid rule: ${rule}`)
 45	  }
 46	
 47	  const addr = rule.slice(0, separatorIndex)
 48	  const prefix = rule.slice(separatorIndex + 1)
 49	  if (prefix.length === 0 || prefix.length > 3) {
 50	    throw new TypeError(`Invalid rule: ${rule}`)
 51	  }
 52	  for (let i = 0; i < prefix.length; i++) {
 53	    const code = prefix.charCodeAt(i)
 54	    if (code < 48 || code > 57) {
 55	      throw new TypeError(`Invalid rule: ${rule}`)
 56	    }
 57	  }
 58	
 59	  return [addr, Number(prefix)]
 60	}
 61	
 62	const buildMatcher = (
 63	  rules: IPRestrictionRule[]
 64	): ((addr: { addr: string; type: AddressType; isIPv4: boolean }) => boolean) => {
 65	  const functionRules: IPRestrictionRuleFunction[] = []
 66	  const staticRules: Set<string> = new Set()
 67	  const cidrRules: [boolean, bigint, bigint][] = []
 68	
 69	  for (let rule of rules) {
 70	    if (rule === '*') {
 71	      return () => true
 72	    } else if (typeof rule === 'function') {
 73	      functionRules.push(rule)
 74	    } else {
 75	      if (rule.includes('/')) {
 76	        const cidrRule = parseCIDRRule(rule)
 77	        if (cidrRule === undefined) {
 78	          throw new TypeError(`Invalid rule: ${rule}`)
 79	        }
 80	        const [addrStr, parsedPrefix] = cidrRule
 81	        const type = distinctRemoteAddr(addrStr)
 82	        if (type === undefined) {
 83	          throw new TypeError(`Invalid rule: ${rule}`)
 84	        }
 85	
 86	        let isIPv4 = type === 'IPv4'
 87	        let prefix = parsedPrefix
 88	        const maxPrefix = isIPv4 ? 32 : 128
 89	        if (prefix > maxPrefix) {
 90	          throw new TypeError(`Invalid rule: ${rule}`)
 91	        }
 92	
 93	        if (prefix === maxPrefix) {
 94	          // this rule is a static rule
 95	          rule = addrStr
 96	        } else {
 97	          let addr = (isIPv4 ? convertIPv4ToBinary : convertIPv6ToBinary)(addrStr)
 98	          if (type === 'IPv6' && isIPv4MappedIPv6(addr) && prefix >= 96) {
 99	            isIPv4 = true
100	            addr = convertIPv4MappedIPv6ToIPv4(addr)
101	            prefix -= 96
102	          }
103	
104	          const mask = ((1n << BigInt(prefix)) - 1n) << BigInt((isIPv4 ? 32 : 128) - prefix)
105	
106	          cidrRules.push([isIPv4, addr & mask, mask] as [boolean, bigint, bigint])
107	          continue
108	        }
109	      }
110	
111	      const type = distinctRemoteAddr(rule)
112	      if (type === undefined) {
113	        throw new TypeError(`Invalid rule: ${rule}`)
114	      }
115	      if (type === 'IPv4') {
116	        staticRules.add(rule)
117	        staticRules.add(`::ffff:${rule}`)
118	      } else {
119	        const ipv6binary = convertIPv6ToBinary(rule)
120	        const ipv6Addr = convertIPv6BinaryToString(ipv6binary)
121	        staticRules.add(ipv6Addr)
122	        if (isIPv4MappedIPv6(ipv6binary)) {
123	          staticRules.add(ipv6Addr.substring(7)) // remove ::ffff: prefix
124	        }
125	      }
126	    }
127	  }
128	
129	  return (remote: {
130	    addr: string
131	    type: AddressType
132	    isIPv4: boolean
133	    binaryAddr?: bigint
134	  }): boolean => {
135	    if (staticRules.has(remote.addr)) {
136	      return true
137	    }
138	    const remoteAddr = (remote.binaryAddr ||= (
139	      remote.isIPv4 ? convertIPv4ToBinary : convertIPv6ToBinary
140	    )(remote.addr))
141	    const remoteIPv4Addr =
142	      remote.isIPv4 || isIPv4MappedIPv6(remoteAddr)
143	        ? remote.isIPv4
144	          ? remoteAddr
145	          : convertIPv4MappedIPv6ToIPv4(remoteAddr)
146	        : undefined
147	    for (const [isIPv4, addr, mask] of cidrRules) {
148	      if (isIPv4) {
149	        if (remoteIPv4Addr === undefined) {
150	          continue
151	        }
152	        if ((remoteIPv4Addr & mask) === addr) {
153	          return true
154	        }
155	        continue
156	      }
157	      if (remote.isIPv4) {
158	        continue
159	      }
160	      if ((remoteAddr & mask) === addr) {
161	        return true
162	      }
163	    }
164	    for (const rule of functionRules) {
165	      if (rule({ addr: remote.addr, type: remote.type })) {
166	        return true
167	      }
168	    }
169	    return false
170	  }
171	}
