/**
 * Utils for IP Addresses
 * @module
 */

import type { AddressType } from '../helper/conninfo'

const parseIPv4ToParts = (ipv4: string): number[] | undefined => {
  const parts = ipv4.split('.')
  if (parts.length !== 4) {
    return
  }

  const parsed: number[] = []
  for (const part of parts) {
    if (part.length === 0 || (part.length > 1 && part[0] === '0')) {
      return
    }

    let value = 0
    for (let i = 0; i < part.length; i++) {
      const code = part.charCodeAt(i)
      if (code < 48 || code > 57) {
        return
      }
      value = value * 10 + code - 48
    }

    if (value > 255) {
      return
    }
    parsed.push(value)
  }

  return parsed
}

const isIPv6Segment = (segment: string): boolean => {
  if (segment.length === 0 || segment.length > 4) {
    return false
  }
  for (let i = 0; i < segment.length; i++) {
    const code = segment.charCodeAt(i)
    if (
      !(
        (code >= 48 && code <= 57) ||
        (code >= 65 && code <= 70) ||
        (code >= 97 && code <= 102)
      )
    ) {
      return false
    }
  }
  return true
}

const parseIPv6ToParts = (ipv6: string): number[] | undefined => {
  let addr = ipv6
  const ipv4Start = ipv6.lastIndexOf(':')
  const hasIPv4Part = ipv6.includes('.')
  const ipv4Parts =
    hasIPv4Part && ipv4Start !== -1 ? parseIPv4ToParts(ipv6.slice(ipv4Start + 1)) : undefined
  if (hasIPv4Part && ipv4Parts === undefined) {
    return
  }
  if (ipv4Parts) {
    addr = `${ipv6.slice(0, ipv4Start)}:${((ipv4Parts[0] << 8) | ipv4Parts[1]).toString(
      16
    )}:${((ipv4Parts[2] << 8) | ipv4Parts[3]).toString(16)}`
  }

  const compressed = addr.split('::')
  if (compressed.length > 2) {
    return
  }

  const left = compressed[0] ? compressed[0].split(':') : []
  const right = compressed.length === 2 && compressed[1] ? compressed[1].split(':') : []
  if (left.some((part) => !isIPv6Segment(part)) || right.some((part) => !isIPv6Segment(part))) {
    return
  }

  if (compressed.length === 1) {
    if (left.length !== 8) {
      return
    }
    return left.map((part) => parseInt(part, 16))
  }

  const zeroCount = 8 - left.length - right.length
  if (zeroCount <= 0) {
    return
  }

  return [
    ...left.map((part) => parseInt(part, 16)),
    ...new Array(zeroCount).fill(0),
    ...right.map((part) => parseInt(part, 16)),
  ]
}

/**
 * Expand IPv6 Address
 * @param ipV6 Shorten IPv6 Address
 * @return expanded IPv6 Address
 */
export const expandIPv6 = (ipV6: string): string => {
  const parts = parseIPv6ToParts(ipV6)
  if (parts === undefined) {
    throw new TypeError(`Invalid IPv6 address: ${ipV6}`)
  }
  return parts.map((part) => part.toString(16).padStart(4, '0')).join(':')
}

/**
 * Distinct Remote Addr
 * @param remoteAddr Remote Addr
 */
export const distinctRemoteAddr = (remoteAddr: string): AddressType => {
  if (parseIPv4ToParts(remoteAddr)) {
    return 'IPv4'
  }
  if (parseIPv6ToParts(remoteAddr)) {
    return 'IPv6'
  }
}

/**
 * Convert IPv4 to Uint8Array
 * @param ipv4 IPv4 Address
 * @returns BigInt
 */
export const convertIPv4ToBinary = (ipv4: string): bigint => {
  const parts = parseIPv4ToParts(ipv4)
  if (parts === undefined) {
    throw new TypeError(`Invalid IPv4 address: ${ipv4}`)
  }
  let result = 0n
  for (let i = 0; i < 4; i++) {
    result <<= 8n
    result += BigInt(parts[i])
  }
  return result
}

/**
 * Convert IPv6 to Uint8Array
 * @param ipv6 IPv6 Address
 * @returns BigInt
 */
export const convertIPv6ToBinary = (ipv6: string): bigint => {
  const parts = parseIPv6ToParts(ipv6)
  if (parts === undefined) {
    throw new TypeError(`Invalid IPv6 address: ${ipv6}`)
  }
  let result = 0n
  for (let i = 0; i < 8; i++) {
    result <<= 16n
    result += BigInt(parts[i])
  }
  return result
}

/**
 * Convert a binary representation of an IPv4 address to a string.
 * @param ipV4 binary IPv4 Address
 * @return IPv4 Address in string
 */
export const convertIPv4BinaryToString = (ipV4: bigint): string => {
  const sections = []
  for (let i = 0; i < 4; i++) {
    sections.push((ipV4 >> BigInt(8 * (3 - i))) & 0xffn)
  }
  return sections.join('.')
}

/**
 * Check if a binary IPv6 address is an IPv4-mapped IPv6 address (::ffff:x.x.x.x)
 * @param ipv6binary binary IPv6 Address
 * @return true if the address is an IPv4-mapped IPv6 address

import { Context } from '../../context'
import type { AddressType, GetConnInfo } from '../../helper/conninfo'
import { Hono } from '../../hono'
import { ipRestriction } from '.'
import type { IPRestrictionRule } from '.'

describe('ipRestriction middleware', () => {
  it('Should restrict', async () => {
    const getConnInfo: GetConnInfo = (c) => {
      return {
        remote: {
          address: c.env.ip,
        },
      }
    }
    const app = new Hono<{
      Bindings: {
        ip: string
      }
    }>()
    app.use(
      '/basic',
      ipRestriction(getConnInfo, {
        allowList: ['192.168.1.0', '192.168.2.0/24'],
        denyList: ['192.168.2.10'],
      })
    )
    app.get('/basic', (c) => c.text('Hello World!'))

    app.use(
      '/allow-empty',
      ipRestriction(getConnInfo, {
        denyList: ['192.168.1.0'],
      })
    )
    app.get('/allow-empty', (c) => c.text('Hello World!'))

    expect((await app.request('/basic', {}, { ip: '0.0.0.0' })).status).toBe(403)

    expect((await app.request('/basic', {}, { ip: '192.168.1.0' })).status).toBe(200)

    expect((await app.request('/basic', {}, { ip: '192.168.2.5' })).status).toBe(200)
    expect((await app.request('/basic', {}, { ip: '192.168.2.10' })).status).toBe(403)

    expect((await app.request('/allow-empty', {}, { ip: '0.0.0.0' })).status).toBe(200)

    expect((await app.request('/allow-empty', {}, { ip: '192.168.1.0' })).status).toBe(403)

    expect((await app.request('/allow-empty', {}, { ip: '192.168.2.5' })).status).toBe(200)
    expect((await app.request('/allow-empty', {}, { ip: '192.168.2.10' })).status).toBe(200)
  })
  it('Custom onerror', async () => {
    const res = await ipRestriction(
      () => '0.0.0.0',
      { denyList: ['0.0.0.0'] },
      () => new Response('error')
    )(new Context(new Request('http://localhost/')), async () => void 0)
    expect(res).toBeTruthy()
    if (res) {
      expect(await res.text()).toBe('error')
    }
  })

  it('Should block invalid remote addresses', async () => {
    const app = new Hono<{
      Bindings: {
        ip: string
      }
    }>()
    app.use(
      '/basic',
      ipRestriction((c) => c.env.ip, {
        allowList: ['::1'],
      })
    )
    app.get('/basic', (c) => c.text('Hello World!'))

    expect((await app.request('/basic', {}, { ip: 'example.com:443' })).status).toBe(403)
    expect((await app.request('/basic', {}, { ip: '1234:::5678' })).status).toBe(403)
    expect((await app.request('/basic', {}, { ip: '::1' })).status).toBe(200)
  })
})

describe('isMatchForRule', () => {
  const isMatch = async (info: { addr: string; type: AddressType }, rule: IPRestrictionRule) => {
    const middleware = ipRestriction(
      () => ({
        remote: {
          address: info.addr,
          addressType: info.type,
        },
      }),
      {
        allowList: [rule],
      }
    )
    try {
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      await middleware(undefined as any, () => Promise.resolve())
    } catch {
      return false
    }
    return true
  }

  it('star', async () => {
    expect(await isMatch({ addr: '192.168.2.0', type: 'IPv4' }, '*')).toBeTruthy()
    expect(await isMatch({ addr: '192.168.2.1', type: 'IPv4' }, '*')).toBeTruthy()
    expect(await isMatch({ addr: '::0', type: 'IPv6' }, '*')).toBeTruthy()
  })
  it('CIDR Notation', async () => {
    expect(await isMatch({ addr: '192.168.2.0', type: 'IPv4' }, '192.168.2.0/24')).toBeTruthy()
    expect(await isMatch({ addr: '192.168.2.1', type: 'IPv4' }, '192.168.2.0/24')).toBeTruthy()
    expect(await isMatch({ addr: '192.168.2.1', type: 'IPv4' }, '192.168.2.1/32')).toBeTruthy()
    expect(await isMatch({ addr: '192.168.2.1', type: 'IPv4' }, '192.168.2.2/32')).toBeFalsy()

    expect(await isMatch({ addr: '::0', type: 'IPv6' }, '::0/1')).toBeTruthy()
    expect(await isMatch({ addr: '::1', type: 'IPv6' }, '0.0.0.0/24')).toBeFalsy()
    expect(await isMatch({ addr: '::abcd:1', type: 'IPv6' }, '127.0.0.0/8')).toBeFalsy()
    expect(await isMatch({ addr: '::1', type: 'IPv6' }, '::ffff:1.0.0.0/96')).toBeFalsy()

    expect(
      await isMatch({ addr: '::ffff:192.168.1.1', type: 'IPv6' }, '::ffff:192.168.1.0/120')
    ).toBeTruthy()
    expect(
      await isMatch({ addr: '192.168.1.1', type: 'IPv4' }, '::ffff:192.168.1.0/120')
    ).toBeTruthy()
    expect(
      await isMatch({ addr: '::ffff:192.168.1.1', type: 'IPv6' }, '192.168.1.0/24')
    ).toBeTruthy()
    expect(await isMatch({ addr: '::ffff:10.0.0.1', type: 'IPv6' }, '192.168.1.0/24')).toBeFalsy()
    expect(await isMatch({ addr: '::ffff:192.168.1.1', type: 'IPv6' }, '::/0')).toBeTruthy()
    expect(
      await isMatch({ addr: '::ffff:192.168.1.1', type: 'IPv6' }, '::ffff:0:0/95')
    ).toBeTruthy()
  })
  it('Invalid CIDR Notation', () => {
    expect(() => ipRestriction(() => '127.0.0.1', { allowList: ['127.0.0.1/'] })).toThrow(
      TypeError
    )
    expect(() => ipRestriction(() => '127.0.0.1', { allowList: ['127.0.0.1/33'] })).toThrow(
      TypeError
    )
    expect(() => ipRestriction(() => '::1', { allowList: ['::1/129'] })).toThrow(TypeError)
    expect(() => ipRestriction(() => '::1', { allowList: ['::1/foo'] })).toThrow(TypeError)
  })
  it('Static Rules', async () => {
    expect(await isMatch({ addr: '192.168.2.1', type: 'IPv4' }, '192.168.2.1')).toBeTruthy()
    expect(await isMatch({ addr: '1234::5678', type: 'IPv6' }, '1234::5678')).toBeTruthy()
    expect(
      await isMatch({ addr: '::ffff:127.0.0.1', type: 'IPv6' }, '::ffff:127.0.0.1')
    ).toBeTruthy()
    expect(await isMatch({ addr: '::ffff:127.0.0.1', type: 'IPv6' }, '::ffff:7f00:1')).toBeTruthy()
    expect(await isMatch({ addr: '127.0.0.1', type: 'IPv4' }, '::ffff:127.0.0.1')).toBeTruthy()
    // IPv4-mapped IPv6 addresses are canonicalized to IPv4
    expect(await isMatch({ addr: '::ffff:127.0.0.1', type: 'IPv6' }, '127.0.0.1')).toBeTruthy()
    expect(await isMatch({ addr: '::ffff:127.0.0.1', type: 'IPv6' }, '127.0.0.2')).toBeFalsy()
    // non-dotted IPv4-mapped forms are not canonicalized (treated as IPv6)
    expect(await isMatch({ addr: '::ffff:7f00:1', type: 'IPv6' }, '127.0.0.1')).toBeFalsy()
    // regular IPv6 is not affected
    expect(await isMatch({ addr: '::1', type: 'IPv6' }, '::1')).toBeTruthy()
  })
  it('Function Rules', async () => {
    expect(await isMatch({ addr: '0.0.0.0', type: 'IPv4' }, () => true)).toBeTruthy()
    expect(await isMatch({ addr: '0.0.0.0', type: 'IPv4' }, () => false)).toBeFalsy()

    const ipaddr = '93.184.216.34'
    await isMatch({ addr: ipaddr, type: 'IPv4' }, (ip) => {
      expect(ipaddr).toBe(ip.addr)
      return false
    })
  })
})

